mapper.select:
WITH UPDATE_DATE AS ( SELECT BRS320.RULE_ID, MAX(BRS340.RS34_Y) AS RS34_Y FROM BRS340TB BRS340, (SELECT BRS320.RS31_1 , SUBSTR(BRS320.RS32_2, INSTR(BRS320.RS32_2, '_') + 1) AS RULE_ID , BRS320.RS32_2 FROM BRS320TB BRS320 WHERE 1 = 1 AND (BRS320.RS32_2 LIKE '혐의거래자#_%' ESCAPE '#' OR BRS320.RS32_2 LIKE '혐의거래내역#_%' ESCAPE '#' OR BRS320.RS32_2 LIKE '기준DATA#_%' ESCAPE '#') ) BRS320 WHERE BRS340.RS31_1 = BRS320.RS31_1 AND BRS340.RS34_U = 2 GROUP BY BRS320.RULE_ID ) SELECT A.*, TO_CHAR(TO_DATE(B.RS34_Y,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS RS34_Y FROM ( SELECT * FROM ( SELECT RULE_ID , RULE_NAME , RULE_DESC , TR_ALERT_CNT /*STR발생건수*/ , ROUND(TR_ALERT_CNT / NVL(TOT_CNT,1) * 100,1) AS TR_RATE /*발생비중*/ , TR_91_CNT + TR_2_CNT AS TR_9_CNT /*처리건수*/ , TR_0_CNT /*미처리*/ , TR_91_CNT /*승인건수*/ , TR_2_CNT /*보고제외(이상없음)건수*/ , TR_KOFIU_CNT /*STR KOFIU 보고건수*/ , ROUND(TR_KOFIU_CNT / DECODE(TR_ALERT_CNT,0,1,TR_ALERT_CNT) * 100,1) AS TR_KOFIU_RATE /*KOFIU 보고비율*/ , ROUND(TR_KOFIU_CNT / DECODE(KOFIU_TOT_CNT,0,1,NVL(KOFIU_TOT_CNT,1)) * 100,1) AS TR_KOFIU_RATE2 /*KOFIU 발생비율*/ FROM (
SELECT T1.RULE_ID , MIN(T1.RULE_NAME) AS RULE_NAME , MIN(T1.RULE_DESC) AS RULE_DESC , SUM(DECODE(T1.RULE_ID,T2.SSPS_TYP_CD,1,0)) AS TR_ALERT_CNT /*STR발생건수*/ , 0 AS TR_9_CNT /*처리건수*/ , SUM(CASE WHEN T2.RPR_PRGRS_CCD NOT IN ('9','99') THEN 1 ELSE 0 END) AS TR_0_CNT /*미처리*/ , SUM(DECODE(T1.RULE_ID,T2.SSPS_TYP_CD,DECODE(T2.OK_CCD,'1',CASE WHEN T2.RPR_PRGRS_CCD IN ('9','99') THEN 1 ELSE 0 END,0),0)) AS TR_91_CNT /*승인건수*/ , SUM(DECODE(T1.RULE_ID,T2.SSPS_TYP_CD,DECODE(T2.OK_CCD,'2',DECODE(T2.RPR_PRGRS_CCD,'9',1,0),0),0)) AS TR_2_CNT /*보고제외(이상없음)건수*/ , SUM(DECODE(T1.RULE_ID,T2.SSPS_TYP_CD,DECODE(T2.RPR_PRGRS_CCD,'99',1,0),0)) AS TR_KOFIU_CNT /*STR KOFIU 보고건수*/ , MAX(T2.TOT_CNT) AS TOT_CNT , MAX(T2.KOFIU_TOT_CNT) AS KOFIU_TOT_CNT , MIN(T1.ASIS_RULE_F) AS ASIS_RULE_F , MIN(T1.SORT_NO) AS SORT_NO FROM ( SELECT MA01_6 AS RULE_ID , BIZ_NM AS RULE_NAME , BIZ_DESC AS RULE_DESC , '0' ASIS_RULE_F , MA01_6 AS SORT_NO FROM C_BIZ A, MMA010TB B WHERE BIZ_ID=RT30_1 AND B.MA01_8 = 'S' UNION ALL SELECT 'KYC0' , '임의보고' , 'STR임의보고' , '0' ASIS_RULE_F , 'R999' AS SORT_NO FROM DUAL ) T1 , ( SELECT SSPS_DL_CRT_CCD , RPR_PRGRS_CCD , SSPS_TYP_CD , OK_CCD , COUNT(*) OVER() AS TOT_CNT , SUM(DECODE(RPR_PRGRS_CCD,'99',1,0)) OVER() AS KOFIU_TOT_CNT FROM NIC66B AA WHERE NVL(INST_ID,0) >= 0 AND SSPS_DL_CRT_CCD IN ('STR','KYC') /* STR */
AND AA.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = AA.SSPS_DL_CRT_DT AND SSPS_DL_ID = AA.SSPS_DL_ID AND SSPS_DL_CRT_CCD = 'STR')
) T2 WHERE T1.RULE_ID = T2.SSPS_TYP_CD GROUP BY T1.RULE_ID ORDER BY T1.RULE_ID ) WHERE 1=1
AND TR_ALERT_CNT >= CASE WHEN (SELECT MA04_3 FROM MMA040TB WHERE MA04_1 = 94) > #{edDate} THEN CASE WHEN ASIS_RULE_F = '0' THEN 1 ELSE 0 END WHEN ASIS_RULE_F = '1' THEN 1 ELSE 0 END
ORDER BY ASIS_RULE_F DESC, SORT_NO ) UNION ALL SELECT '합계' , '' , '' , COUNT(SSPS_TYP_CD) AS TR_ALERT_CNT /*STR발생건수*/ , 100 AS TR_RATE /*발생비중*/ , SUM(DECODE(OK_CCD,'1',CASE WHEN RPR_PRGRS_CCD IN ('9','99') THEN 1 ELSE 0 END,0)) + SUM(DECODE(OK_CCD,'2',DECODE(RPR_PRGRS_CCD,'9',1,0),0)) AS TR_9_CNT /*처리건수*/ , SUM(CASE WHEN RPR_PRGRS_CCD NOT IN ('9','99') THEN 1 ELSE 0 END) AS TR_0_CNT /*미처리*/ , SUM(DECODE(OK_CCD,'1',CASE WHEN RPR_PRGRS_CCD IN ('9','99') THEN 1 ELSE 0 END,0)) AS TR_91_CNT /*승인건수*/ , SUM(DECODE(OK_CCD,'2',DECODE(RPR_PRGRS_CCD,'9',1,0),0)) AS TR_2_CNT /*보고제외(이상없음)건수*/ , SUM(DECODE(RPR_PRGRS_CCD,'99',1,0)) AS TR_KOFIU_CNT /*STR KOFIU 보고건수*/ , ROUND(SUM(DECODE(RPR_PRGRS_CCD,'99',1,0)) / COUNT(SSPS_TYP_CD) * 100,1) AS TR_KOFIU_RATE /*KOFIU 보고비율*/ , 100 AS TR_KOFIU_RATE2 /*KOFIU 발생비율*/ FROM NIC66B AA WHERE NVL(INST_ID,0) >= 0 AND SSPS_DL_CRT_CCD IN ('STR','KYC') /* STR */
AND AA.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = AA.SSPS_DL_CRT_DT AND SSPS_DL_ID = AA.SSPS_DL_ID AND SSPS_DL_CRT_CCD = 'STR')
) A , UPDATE_DATE B WHERE 1=1 AND A.RULE_ID = B.RULE_ID(+)
AND A.RULE_ID IN
#{SSPS_TYP_CD_ARRAY}

SELECT * FROM ( SELECT MN_DL_BRN_CD , MN_DL_BRN_NM , TR_ALERT_CNT /*발생건수*/ , ROUND(TR_ALERT_CNT / NVL(TOT_CNT,1) * 100,2) AS TR_RATE /*발생비중*/ , TR_91_CNT + TR_2_CNT AS TR_9_CNT /*처리건수*/ , TR_0_CNT /*미처리*/ , TR_91_CNT /*승인건수*/ , TR_2_CNT /*보고제외(이상없음)건수*/ , TR_KOFIU_CNT /*KOFIU 보고건수*/ , ROUND(TR_KOFIU_CNT / DECODE(TR_ALERT_CNT,0,1,TR_ALERT_CNT) * 100,2) AS TR_KOFIU_RATE /*KOFIU 보고비율*/ , ROUND(TR_KOFIU_CNT / DECODE(KOFIU_TOT_CNT,0,1,NVL(KOFIU_TOT_CNT,1)) * 100,1) AS TR_KOFIU_RATE2 /*KOFIU 발생비율*/ FROM ( SELECT T2.MN_DL_BRN_CD , MIN(T2.MN_DL_BRN_NM) AS MN_DL_BRN_NM , SUM(1) AS TR_ALERT_CNT /*발생건수*/ , 0 AS TR_9_CNT /*처리건수*/ , SUM(CASE WHEN T2.RPR_PRGRS_CCD NOT IN ('9','99') THEN 1 ELSE 0 END) AS TR_0_CNT /*미처리*/ , SUM(DECODE(T2.OK_CCD,'1',CASE WHEN T2.RPR_PRGRS_CCD IN ('9','99') THEN 1 ELSE 0 END,0)) AS TR_91_CNT /*승인건수*/ , SUM(DECODE(T2.OK_CCD,'2',DECODE(T2.RPR_PRGRS_CCD,'9',1,0),'0')) AS TR_2_CNT /*보고제외(이상없음)건수*/ , SUM(DECODE(T2.RPR_PRGRS_CCD,'99',1,0)) AS TR_KOFIU_CNT /*KOFIU 보고건수*/ , MAX(T2.TOT_CNT) AS TOT_CNT , MAX(T2.KOFIU_TOT_CNT) AS KOFIU_TOT_CNT FROM ( SELECT AA.SSPS_DL_CRT_CCD , AA.RPR_PRGRS_CCD , AA.SSPS_TYP_CD , AA.OK_CCD , AA.SSPS_DL_CRT_DT , AA.SSPS_DL_ID , COUNT(*) OVER() AS TOT_CNT , SUM(DECODE(AA.RPR_PRGRS_CCD,'99',1,0)) OVER() AS KOFIU_TOT_CNT , BB.MN_DL_BRN_CD , BB.MN_DL_BRN_NM FROM NIC66B AA, NIC73B BB WHERE AA.SSPS_DL_CRT_DT = BB.SSPS_DL_CRT_DT AND AA.SSPS_DL_ID = BB.SSPS_DL_ID AND NVL(INST_ID,0) >= 0
AND SSPS_DL_CRT_CCD IN ('STR','KYC') /* STR */
AND SSPS_DL_CRT_CCD IN ('CTR','CAC') /* CTR */
AND BB.MN_DL_BRN_CD = #{branchCode}
AND SSPS_TYP_CD = #{SSPS_TYP_CD}
AND AA.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
) T2 GROUP BY T2.MN_DL_BRN_CD ORDER BY T2.MN_DL_BRN_CD ) ORDER BY MN_DL_BRN_CD ) UNION ALL SELECT '' , '합계' , SUM(1) AS TR_ALERT_CNT /*발생건수*/ , 100 AS TR_RATE /*발생비중*/ , SUM(DECODE(AA.OK_CCD,'1',CASE WHEN AA.RPR_PRGRS_CCD IN ('9','99') THEN 1 ELSE 0 END,0)) + SUM(DECODE(AA.OK_CCD,'2',DECODE(AA.RPR_PRGRS_CCD,'9',1,0),0)) AS TR_9_CNT /*처리건수*/ , SUM(CASE WHEN AA.RPR_PRGRS_CCD NOT IN ('9','99') THEN 1 ELSE 0 END) AS TR_0_CNT /*미처리*/ , SUM(DECODE(AA.OK_CCD,'1',CASE WHEN AA.RPR_PRGRS_CCD IN ('9','99') THEN 1 ELSE 0 END,0)) AS TR_91_CNT /*승인건수*/ , SUM(DECODE(AA.OK_CCD,'2',DECODE(AA.RPR_PRGRS_CCD,'9',1,0),0)) AS TR_2_CNT /*보고제외(이상없음)건수*/ , SUM(DECODE(AA.RPR_PRGRS_CCD,'99',1,0)) AS TR_KOFIU_CNT /*STR KOFIU 보고건수*/ , ROUND(SUM(DECODE(AA.RPR_PRGRS_CCD,'99',1,0)) / SUM(1) * 100,1) AS TR_KOFIU_RATE /*KOFIU 보고비율*/ , 100 AS TR_KOFIU_RATE2 /*KOFIU 발생비율*/ FROM NIC66B AA, NIC73B BB WHERE AA.SSPS_DL_CRT_DT = BB.SSPS_DL_CRT_DT AND AA.SSPS_DL_ID = BB.SSPS_DL_ID AND NVL(INST_ID,0) >= 0
AND SSPS_DL_CRT_CCD IN ('STR','KYC') /* STR */
AND SSPS_DL_CRT_CCD IN ('CTR','CAC') /* CTR */
AND BB.MN_DL_BRN_CD = #{branchCode}
AND SSPS_TYP_CD = #{SSPS_TYP_CD}
AND AA.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}

SELECT /* 문서시작 */ 'CTRSTART' AS CTR00, --문서시작 A.RPR_CCD AS CTR01, --메시지타입
/* 표제부에 관한 정보 */ TRIM(A.RPR_DOC_NO_DL_YR||'-'||LPAD(A.RPR_DOC_NO_FNL_SQ,8,'0')) AS RPR_DOC_NO, --2 문서번호(YYYY A.RPR_DT, -- 보고일자 CASE WHEN A.RPR_CCD NOT IN ('01','99') THEN TRIM(B.RPR_DOC_NO_DL_YR||'-'||LPAD(B.RPR_DOC_NO_FNL_SQ,8,'0')) ELSE '' END AS PRE_RPR_DOC_NO, -- 종전문서번호 LPAD(A.RNM_PR_DL_SQ,3,'0') || '/'|| ( SELECT LPAD(COUNT(*),3,'0') FROM NIC66B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND DL_P_RNMCNO = A.DL_P_RNMCNO AND SSPS_DL_CRT_CCD = A.SSPS_DL_CRT_CCD AND OK_CCD != 2 ) AS TOT_TRAN_SQ, -- 거래순번 TRIM(A.RPR_DOC_NO_DL_YR||'-'||LPAD(A.DOC_SQ,8,'0')) AS BSC_RPR_DOC_NO, -- 기본문서번호
/* I. 보고기관에 관한 정보 */ Z.RPR_OGN_NM AS RPR_OGN_NM, -- 보고기관명 Z.TRNS_OGN_CD AS TRNS_OGN_CD, -- 보고기관코드 Z.RPR_RSPSB_P_NM AS RPR_RSPSB_P_NM, -- 보고책임자명 Z.RPR_CHRG_P_NM AS RPR_CHRG_P_NM, -- 보고담당자명 Z.RPR_CHRG_P_TEL_NO AS RPR_CHRG_P_TEL_NO, -- 보고담당자전화번호
/* II 거래자에 관한 정보 */ /* II-1 공통사항 */ C.DL_P_NM AS DL_P_NM, -- 거래자명 C.DL_P_RNM_NO_CCD, -- 거래자실명번호구분 GET_CODE_NAME('M002',C.DL_P_RNM_NO_CCD) AS DL_P_RNM_NO_NM, -- 거래자실명번호구분명 C.CS_NO, -- 거래자실명번호 C.DL_P_NTNLT_CD, -- 거래자국적코드 GET_CODE_NAME('M004',C.DL_P_NTNLT_CD) AS DL_P_NTNLT_NM, -- 거래자국적명
/* II-2 개인인 경우 */ D.DL_P_HSE_PST_NO, -- 거래자우편번호 D.DL_P_HSE_BSC_ADDR, -- 거래자주소(기본주소) D.DL_P_HSE_DNG_ADDR, -- 거래자주소( D.DL_P_BRTDY, -- 거래자생년월일 DECODE(D.DL_P_SEX_CD,'1','3','2','4') AS DL_P_SEX_CD, -- 성별 D.DL_P_HSE_NATI, -- 거래자자택국가번호 D.DL_P_HSE_AREA, -- 거래자자택지역번호 D.DL_P_HSE_ECNO, -- 거래자자택국번 D.DL_P_HSE_NO, -- 거래자자택번호 D.DL_P_MBL_NATI, -- 거래자핸드폰번호 D.DL_P_MBL_AREA, -- 거래자핸드폰번호 D.DL_P_MBL_ECNO, -- 거래자핸드폰번호 D.DL_P_MBL_NO, -- 거래자핸드폰번호 D.RNM_CMBNTN_NO, -- 실명조합번호 D.DL_P_PSPT_NO, -- 여권번호 CASE WHEN LENGTH(D.OCPTN_CCD) = 1 THEN DECODE(D.OCPTN_CCD,'4','99','0'||D.OCPTN_CCD) ELSE D.OCPTN_CCD END AS OCPTN_CCD, -- 거래자직업구분 D.WP_NM, -- 거래자직장(회사)명 D.IND_TYP_CD, -- 거래자직장업종코드
/* II-3 법인인 경우 */ E.RPRST_P_NM1, -- 대표자명 '99' AS RPRST_RNM_NO_CCD, -- 대표자실명번호구분 '기타' AS RPRST_RNM_NO_NM, -- 대표자실명번호구분명 E.RPRST_P_BRDY1, -- 대표자실명번호 E.RPRST_P_NTNLT_CD1, -- 대표자국적코드 GET_CODE_NAME('M004',E.RPRST_P_NTNLT_CD1) AS RPRST_P_NTNLT_NM, -- 대표자국적명 E.BSNSG_FNDTN_DT, -- 사업체설립일 E.IND_TYP_CD AS BSNSG_IND_TYP_CD, -- 업종코드 E.CORP_RGST_NO, -- 법인등록번호 E.HD_BRNCH_PST_NO, -- 사업체본점우편번호 E.BSNS_CMPNY_PST_NO, -- 사업체사업장우편번호 E.HD_BRNCH_BSC_ADDR, -- 사업체본점주소 E.HD_BRNCH_DNG_ADDR, -- 사업체본점주소 E.BSNS_CMPNY_BSC_ADDR, -- 사업체사업장주소 E.BSNS_CMPNY_DNG_ADDR, -- 사업체사업장주소 E.HD_BRNCH_NATI, -- 사업체본점국가번호 E.HD_BRNCH_AREA, -- 사업체본점지역번호 E.HD_BRNCH_ECNO, -- 사업체본점국번 E.HD_BRNCH_NO, -- 사업체본점번호 E.BSNS_CMPNY_NATI, -- 사업체사업장국가번호 E.BSNS_CMPNY_AREA, -- 사업체사업장지역번호 E.BSNS_CMPNY_ECNO, -- 사업체사업장국번 E.BSNS_CMPNY_NO, -- 사업체사업장번호
/* III 현금거래 내역에 관한 정보 */ /* III-1 공통사항 */ G.DL_DT||LPAD(DL_TM,6,'0') AS DL_DT, -- 거래발생일시 G.HANDLNG_BRN_NM, -- 거래영업점명 G.HANDLNG_BRN_PST_NO, -- 거래영업점우편번호 G.DL_CHNNL_CD AS DL_CHNNL_CD_TEMP, -- 거래채널 DECODE(G.DL_CHNNL_CD,'01','01','02','02','99') AS DL_CHNNL_CD, -- 거래채널 DECODE(G.DL_CHNNL_CD,'01','창구거래','02','자동화기기거래','기타')AS DL_CHNNL_NM, -- 거래채널 '01' AS DL_WY_CD, -- 거래수단 '현금' AS DL_WY_NM, -- 거래수단 G.CSH, -- 거래금액 G.CTR_DL_KND_CD, -- 거래종류 GET_CODE_NAME('M062',G.CTR_DL_KND_CD) AS CTR_DL_KND_NM, -- 거래종류 DECODE(NVL(H.SSPS_DL_CRT_DT,''),'','2','1') AS AC_PRXY_YN, -- 거래대리인존재여부 DECODE(NVL(H.SSPS_DL_CRT_DT,''),'','존재안함','존재') AS VIEW_AC_PRXY_YN, -- 거래대리인존재여부 H.PRXY_NM, -- 거래대리인명 H.PRXY_RNM_NO_CCD, -- 거래대리인실명번호구분 GET_CODE_NAME('M002', H.PRXY_RNM_NO_CCD) AS PRXY_RNM_NO_NM, -- 거래대리인 실명확인 구분 H.PRXY_CS_NO, -- 거래대리인실명번호 H.PRXY_NATI, -- 거래대리인연락처국가번호 H.PRXY_AREA, -- 거래대리인연락처지역번호 H.PRXY_ECNO, -- 거래대리인연락처국번 H.PRXY_NO, -- 거래대리인연락처번호 H.PRXY_NTNLT_CD, -- 거래대리인국적코드 GET_CODE_NAME('M004',H.PRXY_NTNLT_CD) AS PRXY_NTNLT_NM, -- 거래대리인국적명
H.AC_OWN_P_RLTNS_CD AS AC_OWN_P_RLTNS_CD_TEMP, -- 거래대리인거래자와관계코드 NVL((SELECT TRNSFRM_CD FROM NIC95B WHERE CD='L058' AND CD_VL9 = H.AC_OWN_P_RLTNS_CD), '98') AS AC_OWN_P_RLTNS_CD, -- 거래대리인거래자와관계코드 NVL((SELECT TRNSFRM_CD_EXPL FROM NIC95B WHERE CD='L058' AND CD_VL9 = H.AC_OWN_P_RLTNS_CD), '알수없음') AS AC_OWN_P_RLTNS_NM, -- 거래대리인거래자와관계명
/* III-2 계좌거래의 경우 */ L.ACNT_NO, -- 관련계좌번호 L.AC_OPN_BRN_NM, -- 계좌개설점 L.AC_OPN_BRN_PST_NO, -- 계좌개설점우편번호 L.AC_OPN_DT, -- 계좌개설일 DECODE(NVL(I.SSPS_DL_CRT_DT,''),'','2','1') AS PRXY_YN, -- 계좌대리인존재여부 DECODE(NVL(I.SSPS_DL_CRT_DT,''),'','존재안함','존재') AS VIEW_PRXY_YN, -- 계좌대리인존재여부 I.PRXY_NM AS GNL_PRXY_NM, -- 계좌대리인명 I.PRXY_RNM_NO_CCD AS GNL_PRXY_RNM_NO_CCD, -- 계좌대리인실명번호구분 GET_CODE_NAME('M002', I.PRXY_RNM_NO_CCD) AS GNL_PRXY_RNM_NO_NM, I.PRXY_CS_NO AS GNL_PRXY_CS_NO, -- 계좌대리인실명번호 I.PRXY_CNTY_NATI_CRYP, -- 계좌대리인연락처국가번호 I.PRXY_CNTY_AREA_CRYP, -- 계좌대리인연락처지역번호 I.PRXY_CNTY_ECNO_CRYP, -- 계좌대리인연락처국번 I.PRXY_CNTY_NO_CRYP, -- 계좌대리인연락처번호 I.PRXY_NTNLT_CD AS GNL_PRXY_NTNLT_CD, -- 계좌대리인국적코드 GET_CODE_NAME('M004',I.PRXY_NTNLT_CD) AS GNL_PRXY_NTNLT_NM, -- 계좌대리인국적명
I.AC_OWN_P_RLTNS_CD AS GNL_RLTNS_TEMP, -- 계좌대리인관계코드 NVL((SELECT TRNSFRM_CD FROM NIC95B WHERE CD='L058' AND CD_VL9 = I.AC_OWN_P_RLTNS_CD), '98') AS GNL_RLTNS_CD, NVL((SELECT TRNSFRM_CD_EXPL FROM NIC95B WHERE CD='L058' AND CD_VL9 = I.AC_OWN_P_RLTNS_CD), '알수없음') AS GNL_RLTNS_NM,
/* III-3 유가증권거래의 경우 */ J.CHCK_KND_CD, -- 관련유가증권종류 GET_CODE_NAME('M052', J.CHCK_KND_CD) AS CHCK_KND_NM, -- 관련유가증권종류 J.CHCK_STRT_NO, -- 관련유가증권시작번호 J.CHCK_END_NO, -- 관련유가증권끝번호
/* III-4 자기앞수표거래의 경우 */ J.BNK_NM, -- 현금지급은행명 J.BNK_CD, -- 현금지급은행기관코드 J.BRN_NM, -- 현금지급영업점명 J.BRN_PST_NO, -- 현금지급영업점우편번호
/* IV 수취인 계좌에 관한 정보 */ K.CPRTY_TRSNS_AC_NO, -- 수취인계좌번호 K.CPRTY_TRSNS_FOGN_NM, -- 수취금융기관명 K.CPRTY_TRSNS_OGN_CD, -- 수취금융기관코드 K.CPRTY_TRSNS_AC_NM, -- 수취인성명
/* 취소 또는 정정 보고에 관한 정보 */ CASE WHEN A.RPR_CCD NOT IN ('01','93') THEN ( SELECT CNTNT FROM NIC66B_W WHERE (INST_ID,WORK_ID) IN ( SELECT INST_ID,MIN(WORK_ID) FROM NIC66B_W WHERE INST_ID = A.INST_ID GROUP BY INST_ID ) ) ELSE '' END AS VIEW_COMMENT, 'CTREND' AS CTR83 FROM NIC66B A, NIC84B B, NIC70B C, NIC78B D, NIC79B E, NIC71B F, NIC75B G, NIC98B H, NIC72B I, ( SELECT B.SSPS_DL_CRT_DT, B.SSPS_DL_ID, B.GNL_AC_NO, B.GDS_NO, B.DL_DT, B.DL_SQ, C.CHCK_KND_CD, C.CHCK_STRT_NO, C.CHCK_END_NO, DECODE(C.CHCK_KND_CD, '05', Z.RPR_OGN_NM, '') AS BNK_NM, DECODE(C.CHCK_KND_CD, '05', Z.TRNS_OGN_CD, '') AS BNK_CD, DECODE(C.CHCK_KND_CD, '05', B.HANDLNG_BRN_NM, '') AS BRN_NM, DECODE(C.CHCK_KND_CD, '05', B.HANDLNG_BRN_PST_NO, '') AS BRN_PST_NO FROM NIC71B A, NIC75B B, NIC76B C, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT(+) AND B.SSPS_DL_ID = C.SSPS_DL_ID(+) AND B.GNL_AC_NO = C.GNL_AC_NO(+) AND B.DL_DT = C.DL_DT(+) AND B.DL_SQ = C.DL_SQ(+) AND B.CTR_DL_KND_CD IN ('25','26') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) J,--수표정보 ( SELECT B.SSPS_DL_CRT_DT, B.SSPS_DL_ID, B.GNL_AC_NO, B.GDS_NO, B.DL_DT, B.DL_SQ, NVL(C.CPRTY_TRSNS_AC_NO,A.ACNT_NO) AS CPRTY_TRSNS_AC_NO, NVL(C.CPRTY_TRSNS_FOGN_NM,Z.RPR_OGN_NM) AS CPRTY_TRSNS_FOGN_NM, NVL(C.CPRTY_TRSNS_OGN_CD,Z.TRNS_OGN_CD) AS CPRTY_TRSNS_OGN_CD, NVL(C.CPRTY_TRSNS_AC_NM,A.CS_NM) AS CPRTY_TRSNS_AC_NM FROM NIC71B A, NIC75B B, NIC83B C, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT(+) AND B.SSPS_DL_ID = C.SSPS_DL_ID(+) AND B.GNL_AC_NO = C.GNL_AC_NO(+) AND B.DL_DT = C.DL_DT(+) AND B.DL_SQ = C.DL_SQ(+) AND B.CTR_DL_KND_CD IN ('21','22') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) K,
( SELECT A.* FROM NIC71B A, NIC75B B WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.CTR_DL_KND_CD IN ('11','12') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) L,
NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = B.SSPS_DL_ID(+)
AND A.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = C.DL_P_RNMCNO
AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = D.DL_P_RNMCNO(+) AND C.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = E.DL_P_RNMCNO(+)
AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = F.SSPS_DL_ID
AND F.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND F.SSPS_DL_ID = G.SSPS_DL_ID AND F.GNL_AC_NO = G.GNL_AC_NO
AND F.SSPS_DL_CRT_DT = L.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = L.SSPS_DL_ID(+) AND F.GNL_AC_NO = L.GNL_AC_NO(+)
AND G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = H.SSPS_DL_ID(+) AND G.GNL_AC_NO = H.GNL_AC_NO(+) AND G.DL_DT = H.DL_DT(+) AND G.DL_SQ = H.DL_SQ(+)
AND F.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = I.SSPS_DL_ID(+) AND F.GNL_AC_NO = I.GNL_AC_NO(+)
AND G.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = J.SSPS_DL_ID(+) AND G.GNL_AC_NO = J.GNL_AC_NO(+) AND G.DL_DT = J.DL_DT(+) AND G.DL_SQ = J.DL_SQ(+)
AND G.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = K.SSPS_DL_ID(+) AND G.GNL_AC_NO = K.GNL_AC_NO(+) AND G.DL_DT = K.DL_DT(+) AND G.DL_SQ = K.DL_SQ(+)
AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}
